'use client'

import Image from 'next/image'
import { useState } from 'react'

import { ScrollFadeEdges } from '@/components/flx/blocks/shared/scroll-fade-edges'
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { cn } from '@/lib/utils'

export interface TabsMediaItem {
  label: string
  url: string
}

export interface TabsMediaProps {
  title?: string
  description?: string
  items: TabsMediaItem[]
}

export function TabsMedia({
  title,
  description,
  items,
}: Readonly<TabsMediaProps>) {
  const [activeIndex, setActiveIndex] = useState(0)
  const safeIndex = Math.min(activeIndex, Math.max(0, items.length - 1))

  if (!items.length) return null

  return (
    <div className="flex w-full flex-col gap-5">
      {(title || description) && (
        <header className="flex flex-col gap-2 text-center">
          {title && <h2 className="text-2xl font-bold">{title}</h2>}
          {description && (
            <p className="text-muted-foreground text-sm">{description}</p>
          )}
        </header>
      )}

      <Tabs
        value={String(safeIndex)}
        onValueChange={(value) => setActiveIndex(Number(value))}
        className="items-center gap-8"
      >
        <ScrollFadeEdges
          direction="horizontal"
          className="w-full"
          scrollClassName="flex no-scrollbar p-1"
          fadeWidth={50}
        >
          <TabsList className="mx-auto h-auto gap-3 bg-transparent p-0 shadow-none">
            {items.map((tab, index) => (
              <TabsTrigger
                key={`${index}-${tab.label}`}
                value={String(index)}
                className="text-muted-foreground data-[state=active]:text-foreground data-[state=active]:bg-muted hover:bg-muted hover:text-foreground dark:data-[state=active]:bg-accent dark:hover:text-foreground rounded-2xl border-none bg-transparent px-3 py-2 text-sm shadow-none transition-colors data-[state=active]:font-medium data-[state=active]:shadow-none group-data-[variant=default]/tabs-list:data-[state=active]:shadow-none"
              >
                {tab.label}
              </TabsTrigger>
            ))}
          </TabsList>
        </ScrollFadeEdges>

        <div className="relative aspect-square max-h-120 min-h-100 w-full overflow-hidden rounded-2xl 2xl:max-h-150">
          {items.map((item, index) => (
            <div
              key={`${index}-${item.url}`}
              className={cn(
                'absolute inset-0 transition-opacity duration-500',
                index === safeIndex ? 'opacity-100' : 'opacity-0',
              )}
            >
              <Image
                src={item.url}
                alt={item.label}
                fill
                className="object-cover"
                sizes="100vw"
                priority={index === 0}
                unoptimized
              />
            </div>
          ))}
        </div>
      </Tabs>
    </div>
  )
}

import { TabsMedia, type TabsMediaProps } from './tabs-media'

export function TabsMediaExample() {
  const values = {
    title: 'Built to ship faster',
    description:
      'Everything you need to build modern interfaces. From design tokens to ready-made blocks.',
    items: [
      {
        label: 'Design',
        url: 'https://images.unsplash.com/photo-1635746065098-a0ae3eadfa6f?q=80&w=1332&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D',
      },
      {
        label: 'Components',
        url: 'https://images.unsplash.com/photo-1530912780732-0d2507ded3e8?q=80&w=1170&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D',
      },
      {
        label: 'Developer Experience',
        url: 'https://images.unsplash.com/photo-1719448683263-8424028681f2?q=80&w=1170&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D',
      },
      {
        label: 'Customization',
        url: 'https://images.unsplash.com/photo-1666529529871-a619c5a1a2b1?q=80&w=1170&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D',
      },
      {
        label: 'Performance',
        url: 'https://images.unsplash.com/photo-1551777995-e47e7ba6d1f0?q=80&w=1170&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D',
      },
      {
        label: 'Accessibility',
        url: 'https://images.unsplash.com/photo-1604181941498-d7b7acc8a160?q=80&w=1170&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D',
      },
    ],
  } satisfies TabsMediaProps

  return (
    <TabsMedia
      title={values.title}
      description={values.description}
      items={values.items}
    />
  )
}
